-- Set programs that you use
local terminal = "alacritty"
local menu = "rofi -show drun"
local browser = "zen-browser"
local lock = "hyprlock"
local pass = "~/.config/scripts/rofi_keepassxc -d ~/.config/keepassxc/Passwords.kdbx"
local files = "rofi -show filebrowser"
local wsmgr = "~/.config/scripts/rofi_workspace_manager"

